class IoTDeviceController:
    def __init__(self, pin_no=2, active_high=True):
        self.pin = machine.Pin(pin_no, machine.Pin.OUT)
        self.active_high = active_high
        self.state = False
        self.turn_off()

    def _write(self, on):
        self.state = bool(on)
        if self.active_high:
            self.pin.value(1 if self.state else 0)
        else:
            self.pin.value(0 if self.state else 1)

    def turn_on(self):
        self._write(True)

    def turn_off(self):
        self._write(False)

    def toggle(self):
        self._write(not self.state)

    def status(self):
        return {
            "device": "esp32",
            "state": "on" if self.state else "off",
            "free_mem": gc.mem_free(),
            "ticks_ms": utime.ticks_ms(),
        }


class WebSocketServer:
    def __init__(self, host="0.0.0.0", port=80, controller=None):
        self.host = host
        self.port = port
        self.controller = controller or IoTDeviceController()
